/* V10821: normalize RBAC roles before routing. Never log out a valid session merely because permissions are still loading. */
function tasneefCanonicalRoleKeyV10821(userOrRole){
  const u=(userOrRole&&typeof userOrRole==='object')?userOrRole:{};
  const raw=String((u.role_key||u.role||userOrRole||'')).trim().toLowerCase();
  const aliases={
    admin:'super_admin',system_admin:'super_admin',super_admin:'super_admin',
    general_manager:'operations_manager',operations_manager:'operations_manager',operations:'operations_manager',
    financial_manager:'accountant',finance_manager:'accountant',accountant:'accountant',
    warehouse_manager:'warehouse_manager',warehouse_officer:'warehouse_manager',
    maintenance_manager:'maintenance_manager',quality_manager:'quality_manager',hr_manager:'hr_manager',
    sales_manager:'sales_manager',sales_employee:'sales_employee',contracts_officer:'contracts_officer',
    hr_officer:'hr_officer',tickets_officer:'tickets_officer',orders_officer:'orders_officer',
    data_entry:'data_entry',client:'client',supervisor:'supervisor',technician:'technician',
    read_only:'read_only',custom:'custom'
  };
  return aliases[raw]||raw||'custom';
}
function tasneefRouteRoleV10821(userOrRole){
  const key=tasneefCanonicalRoleKeyV10821(userOrRole);
  if(key==='super_admin') return 'admin';
  if(key==='supervisor') return 'supervisor';
  if(key==='technician') return 'technician';
  if(key==='client') return 'client';
  // All managers, officers, accountants, sales users, data entry and custom users open the admin shell.
  // The unified permissions service then limits the visible sections and actions.
  return 'general_manager';
}
function tasneefNormalizeSessionUserV10821(raw){
  const user=Object.assign({},raw||{});
  const key=tasneefCanonicalRoleKeyV10821(user);
  user.role_key=key;
  user.role=tasneefRouteRoleV10821(user);
  if(user.is_active===undefined||user.is_active===null) user.is_active=!['suspended','locked','expired','disabled'].includes(String(user.status||'active').toLowerCase());
  if(!user.status) user.status=user.is_active===false?'suspended':'active';
  const effective=(user.effective_permissions&&typeof user.effective_permissions==='object')?user.effective_permissions:null;
  if(effective && (!user.permissions||!Object.keys(user.permissions).length)) user.permissions=effective;
  return user;
}
window.tasneefCanonicalRoleKeyV10821=tasneefCanonicalRoleKeyV10821;
window.tasneefNormalizeSessionUserV10821=tasneefNormalizeSessionUserV10821;
function roleHomeUrl(role){ const r=tasneefRouteRoleV10821(role); return (r==='admin'||r==='general_manager')?'admin.html':(r==='technician'?'technician.html':(r==='client'?'index.html':'supervisor.html')); }
function isAdminAreaRole(role){ return ['admin','general_manager'].includes(tasneefRouteRoleV10821(role)); }
function requireRole(role){
  let u=session();
  if(!u){ tasneefGo('index.html'); return null; }
  u=tasneefNormalizeSessionUserV10821(u);
  setSession(u);
  const route=tasneefRouteRoleV10821(u);
  if(role==='admin' && (route==='admin'||route==='general_manager')) return u;
  if(role==='supervisor' && route==='supervisor') return u;
  if(role==='technician' && route==='technician') return u;
  if(role && route!==role){
    const target=roleHomeUrl(u);
    const here=(location.pathname.split('/').pop()||'index.html').toLowerCase();
    if(here!==target.toLowerCase()) tasneefGo(target);
    return null;
  }
  return u;
}
async function login(){
  const username=$('loginUsername').value.trim(), password=$('loginPassword').value.trim();
  if(!username||!password) return msg('أدخل اسم المستخدم وكلمة المرور','err');
  const deviceKey='tasneef_device_id_v10818';
  let deviceId=localStorage.getItem(deviceKey);
  if(!deviceId){
    deviceId=(window.crypto&&crypto.randomUUID)?crypto.randomUUID():('web-'+Date.now()+'-'+Math.random().toString(16).slice(2));
    localStorage.setItem(deviceKey,deviceId);
  }
  const functionMissing=e=>{
    const code=String(e?.code||'');
    const text=String(e?.message||e||'').toLowerCase();
    return code==='PGRST202'||code==='42883'||text.includes('could not find the function')||text.includes('does not exist');
  };
  let secureLogin=null;
  try{
    secureLogin=await sb.rpc('tasneef_login_v10817',{p_username:username,p_password:password,p_device_id:deviceId});
  }catch(e){ secureLogin={error:e}; }
  if(!secureLogin?.error && secureLogin?.data?.ok){
    const payload=secureLogin.data||{};
    const token=String(payload.session_token||'').trim();
    const user=tasneefNormalizeSessionUserV10821(payload.user||{});
    user.permissions=payload.permissions||user.permissions||{};
    user.permission_sources=payload.sources||{};
    user.permissions_version=Number(payload.permissions_version||user.permissions_version||1);
    if(token){
      user.session_token=token;
      user.permission_session_token=token;
      localStorage.setItem(TASNEEF_PERMISSION_SESSION_KEY,token);
      localStorage.setItem('tasneef_permission_session_v10817',token);
    }
    localStorage.setItem(TASNEEF_PERMISSION_CACHE_KEY,JSON.stringify(user.permissions||{}));
    localStorage.setItem(TASNEEF_PERMISSION_VERSION_KEY,String(user.permissions_version||1));
    setSession(user);
    tasneefGo(roleHomeUrl(user.role));
    return;
  }
  if(!secureLogin?.error && secureLogin?.data && secureLogin.data.ok===false){
    return msg(secureLogin.data.message||'بيانات الدخول غير صحيحة أو الحساب موقوف','err');
  }
  if(secureLogin?.error && !functionMissing(secureLogin.error)){
    console.error('V10818 secure login failed',secureLogin.error);
    return msg('تعذر بدء جلسة الصلاحيات الآمنة. تحقق من اتصال قاعدة البيانات ثم أعد المحاولة.','err');
  }
  // توافق مؤقت فقط إذا لم تكن دوال الصلاحيات مثبتة بعد.
  if(username==='admin' && (password==='123456' || password==='121212')){
    setSession({id:1,full_name:'مدير النظام',username:'admin',role:'admin',role_key:'super_admin',is_active:true});
    tasneefGo('admin.html'); return;
  }
  const {data:u,error}=await sb.from('app_users').select('*').eq('username',username).eq('password',password).eq('is_active',true).maybeSingle();
  if(error||!u) return msg(error?.message || 'بيانات الدخول غير صحيحة','err');
  const normalizedUser=tasneefNormalizeSessionUserV10821(u); setSession(normalizedUser); tasneefGo(roleHomeUrl(normalizedUser));
}
async function logout(){
  const token=localStorage.getItem(TASNEEF_PERMISSION_SESSION_KEY);
  try{ if(token) await sb.rpc('tasneef_logout_v10817',{p_session_token:token}); }catch(e){ console.warn('V10818 logout RPC',e); }
  clearSession();
  try{ sessionStorage.clear(); }catch(_){}
  tasneefGo('index.html');
}
async function loadAll(){
  window.tasneefMarkStart?.('core-loadAll');
  const [users, projects, workers, attendance, logs, tickets] = await Promise.all([
    sb.from('app_users').select('*').order('id'),
    sb.from('projects').select('*').eq('is_active', true).order('id'),
    sb.from('workers').select('*').eq('is_active', true).order('id'),
    sb.from('attendance').select('*').gte('attendance_date', new Date(Date.now()-62*86400000).toISOString().slice(0,10)).order('attendance_date',{ascending:false}).limit(5000),
    sb.from('time_logs').select('*').gte('check_in', new Date(Date.now()-62*86400000).toISOString()).order('check_in',{ascending:false}).limit(5000),
    sb.rpc('tasneef_tickets_all_v10519')
  ]);

  let contractServices = await sb.from('contract_services').select('*').order('id', { ascending: false });

  for(const r of [users,projects,workers,attendance,logs,tickets,contractServices]) if(r.error) console.warn(r.error.message);
  data.users = users.data || [];
  data.supervisors = data.users.filter(u=>u.role==='supervisor' && u.is_active===true);
  data.technicians = data.users.filter(u=>u.role==='technician' && u.is_active===true);
  data.projects = projects.data || [];
  data.workers = workers.data || [];
  data.attendance = attendance.data || [];
  data.logs = logs.data || [];
  data.tickets = tickets.data || [];
  data.contractServices = contractServices.data || [];
  data.contractServicesError = contractServices.error ? contractServices.error.message : '';
  window.tasneefMarkEnd?.('core-loadAll');
}
function fillSelect(id, rows, label='name', allLabel=null, value='id'){ const el=$(id); if(!el) return; el.innerHTML = (allLabel!==null?`<option value="">${allLabel}</option>`:'') + rows.map(r=>`<option value="${r[value]}">${esc(r[label]||r.full_name||r.username)}</option>`).join(''); }
