  const E = v => S(v).replace(/[&<>"']/g, m => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
  const say = (t,type) => { try{ if(typeof msg === 'function') msg(t,type); else alert(t); }catch(_){ alert(t); } };
