  function sName(id){ try{ if(typeof supervisorName==='function') return supervisorName(id); }catch(e){} const u=A(D().supervisors).concat(A(D().users)).find(x=>S(x.id)===S(id)); return u?.full_name || u?.name || u?.username || S(id||'-'); }
