    const project=r['ط§ظ„ظ…ط´ط±ظˆط¹']||'-', client=r['ط§ط³ظ… ط§ظ„ط¹ظ…ظٹظ„']||'-', phone=r['ط±ظ‚ظ… ط§ظ„ط¹ظ…ظٹظ„']||'-';
