    head.innerHTML='<tr><th>اسم العامل</th><th>النوع</th><th>المشرف</th><th>المشروع</th>'+Array.from({length:days},(_,i)=>`<th>${String(i+1).padStart(2,'0')}</th>`).join('')+'<th>حضور</th><th>غياب</th><th>إجازة</th><th>نقل</th><th>النسبة</th></tr>';
