  const BUILD='v10182_ATTENDANCE_NAMES_ONCE_KEEP_RECORDS';
  const $id = id => document.getElementById(id);
  const A = v => Array.isArray(v)?v:[];
  const S = v => String(v ?? '').trim();
  const E = s => S(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  const ds = () => window.data || {attendance:[],workers:[],projects:[],users:[],supervisors:[]};
  function todayStr(){ try{return today()}catch(_){return new Date().toISOString().slice(0,10)} }
  function norm(v){ return S(v).toLowerCase().replace(/[إأآا]/g,'ا').replace(/[ىي]/g,'ي').replace(/ة/g,'ه').replace(/[\u064B-\u0652]/g,'').replace(/[^\p{L}\p{N}]+/gu,' ').replace(/\s+/g,' ').trim(); }
  function sid(v){ return S(v); }
  function workerRow(wid){ return A(ds().workers).find(w=>sid(w.id)===sid(wid)) || {}; }
  function projectRow(pid){ return A(ds().projects).find(p=>sid(p.id)===sid(pid)) || {}; }
  function userRow(uid){ return A(ds().users).find(u=>sid(u.id)===sid(uid)) || A(ds().supervisors).find(u=>sid(u.id)===sid(uid)) || {}; }
  function workerNameFromRecord(r){ const w=workerRow(r&&r.worker_id); return S(w.name||w.full_name||r?.worker_name||r?.name||r?.worker||''); }
  function workerKeyByName(rOrWorker){ const name=S(rOrWorker?.name||rOrWorker?.full_name||workerNameFromRecord(rOrWorker)); return norm(name) || ('id:'+sid(rOrWorker?.worker_id||rOrWorker?.id||'')); }
  function recDate(r){ return S(r?.attendance_date || r?.date || r?.work_date || r?.created_at).slice(0,10); }
  function recMonth(r){ return recDate(r).slice(0,7); }
  function projectId(r){ const w=workerRow(r?.worker_id); return r?.project_id || r?.assigned_project_id || w.project_id || w.assigned_project_id || ''; }
  function supervisorId(r){ const w=workerRow(r?.worker_id); const p=projectRow(projectId(r)); return r?.supervisor_id || r?.app_supervisor_id || w.supervisor_id || w.app_supervisor_id || p.supervisor_id || ''; }
  function pName(pid){ const p=projectRow(pid); try{return projectName(pid)||S(p.name||p.project_name||pid||'-')}catch(_){return S(p.name||p.project_name||pid||'-')||'-'} }
  function sName(uid){ const u=userRow(uid); try{return supervisorName(uid)||S(u.full_name||u.name||u.username||uid||'-')}catch(_){return S(u.full_name||u.name||u.username||uid||'-')||'-'} }
