  function uniqueText(vals){ const out=[], seen=new Set(); vals.map(S).filter(Boolean).forEach(v=>{const k=norm(v); if(k&&!seen.has(k)){seen.add(k); out.push(v);}}); return out.join('، ') || '-'; }
  function statusInfo(st){ const x=norm(st); if(['present','حاضر','حضور','1','true'].includes(x)) return {short:'ح',label:'حاضر',cell:'att-present',cls:'green',rank:3}; if(['absent','غائب','غياب','0','false'].includes(x)) return {short:'غ',label:'غائب',cell:'att-absent',cls:'red',rank:2}; if(['leave','اجازه','اجازة','اجازه رسميه','إجازة'].map(norm).includes(x)) return {short:'ج',label:'إجازة',cell:'att-leave',cls:'amber',rank:1}; if(['transfer','نقل','منقول'].includes(x)) return {short:'ن',label:'نقل',cell:'att-transfer',cls:'',rank:1}; return {short:'-',label:'لم يسجل',cell:'att-empty',cls:'',rank:0}; }
  function bestRecord(records){ return A(records).slice().sort((a,b)=>Number(b?.id||0)-Number(a?.id||0))[0] || {}; }
  function bestStatusRecord(records){ return A(records).slice().sort((a,b)=>{ const ra=statusInfo(a?.status).rank, rb=statusInfo(b?.status).rank; if(rb!==ra) return rb-ra; return Number(b?.id||0)-Number(a?.id||0); })[0] || {}; }
  function matchesSupervisor(r, selected){ if(!selected) return true; return sid(supervisorId(r))===sid(selected) || sid(r?.supervisor_id)===sid(selected); }
  function setSupervisorSelect(id){ const el=$id(id); if(!el) return ''; const old=el.value||''; const rows=[...A(ds().supervisors),...A(ds().users).filter(u=>S(u.role)==='supervisor')]; A(ds().attendance).forEach(a=>{ const x=supervisorId(a); if(x) rows.push({id:x,full_name:sName(x)}); }); const seen=new Set(); const opts=rows.filter(x=>x&&x.id!=null&&!seen.has(sid(x.id))&&(seen.add(sid(x.id)),true)).map(x=>`<option value="${E(x.id)}">${E(x.full_name||x.name||x.username||x.id)}</option>`).join(''); const html='<option value="">كل المشرفين</option>'+opts; if(el.dataset.v10182Html!==html){el.innerHTML=html; el.dataset.v10182Html=html;} if([...el.options].some(o=>o.value===old)) el.value=old; return el.value||''; }
  function daysInMonth(month){ const y=Number(S(month).slice(0,4)), m=Number(S(month).slice(5,7)); return new Date(y,m,0).getDate()||31; }
  function dateOf(month,d){ return S(month)+'-'+String(d).padStart(2,'0'); }
