      const projects=uniqueText(g.records.map(projectId).filter(Boolean).map(pName)); const sups=uniqueText(g.records.map(supervisorId).filter(Boolean).map(sName)); const shifts=uniqueText(g.records.map(x=>extractShift(x.notes)).filter(Boolean)); const notes=uniqueText(g.records.map(x=>cleanNote(x.notes)).filter(Boolean));
