  function diffTxt(d){ try{ if(typeof window.diffText==='function') return window.diffText(d); }catch(_){} return Math.abs(d)<=5?'0 دقيقة':(d>0?'زيادة ':'نقص ')+minsTxt(Math.abs(d)); }
  function timeTxt(v){ try{ if(typeof window.timeOnly==='function') return window.timeOnly(v); }catch(_){} if(!v) return '-'; const d=new Date(v); if(!isNaN(d)){ let h=d.getHours(), m=d.getMinutes(), s=h<12?'ص':'م'; h=h%12||12; return h+':'+String(m).padStart(2,'0')+' '+s; } return S(v); }
