  window.copyUserPermissionsV10700=function(id){const u=(window.data?.users||[]).find(x=>String(x.id)===String(id));if(!u)return;localStorage.setItem('tasneef_permissions_clipboard_v10700',JSON.stringify({permissions:u.permissions||{},scope_type:u.scope_type,allowed_project_ids:u.allowed_project_ids||[]}));msg('تم نسخ الصلاحيات والنطاق. افتح المستخدم الهدف ثم الصقها من المعاينة.');};
