      const s=await openStatus(null,true);if(s?.open_record&&S(s.open_record.project_id)!==S(pid))return notify(`لديك تسجيل مفتوح في مشروع ${s.project?.name||s.open_record.project_name||''}. سجّل الخروج أولًا.`,'err');
